mapper.select:
SELECT
admin_id as adminId,
admin_name as adminName,
admin_password as adminPassword,
admin_state as adminState,
create_time as createTime
FROM admin



        AND admin_name LIKE concat('%', #{name}, '%')



        AND create_time >= #{btime}



        AND create_time <= #{etime}



        AND admin_state = #{state}



LIMIT  #{start}, #{end}
